import { describe, it } from "vitest";
import assert from "node:assert/strict";
import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const repoRoot = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..");
const packRoot = path.join(repoRoot, "market-packs", "pr-walkthrough");
const packSrc = path.join(packRoot, "src");
const sharedRoot = path.join(repoRoot, "src", "shared");
const forbiddenCoreRoots = [
	path.join(repoRoot, "src", "ui"),
	path.join(repoRoot, "src", "app"),
	path.join(repoRoot, "src", "server"),
];

type ImportSite = {
	file: string;
	specifier: string;
	kind: "static" | "dynamic";
};

function normalizePath(p: string): string {
	return path.relative(repoRoot, p).split(path.sep).join("/");
}

function isInDir(file: string, dir: string): boolean {
	const relative = path.relative(dir, file);
	return relative === "" || (!relative.startsWith("..") && !path.isAbsolute(relative));
}

function walkSourceFiles(dir: string): string[] {
	const files: string[] = [];
	for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
		const full = path.join(dir, entry.name);
		if (entry.isDirectory()) {
			files.push(...walkSourceFiles(full));
		} else if (/\.[cm]?[jt]s$/.test(entry.name) && !entry.name.endsWith(".d.ts")) {
			files.push(full);
		}
	}
	return files;
}

function stripComments(source: string): string {
	return source
		.replace(/\/\*[\s\S]*?\*\//g, "")
		.replace(/(^|[^:])\/\/.*$/gm, "$1");
}

function collectImports(file: string, source: string): ImportSite[] {
	const imports: ImportSite[] = [];
	const text = stripComments(source);
	const staticImportOrExport = /\b(?:import|export)\s+(?!\()(?<body>[\s\S]*?);/g;
	for (const match of text.matchAll(staticImportOrExport)) {
		const body = (match.groups?.body ?? "").trim();
		const sideEffectImport = body.match(/^['"](?<specifier>[^'"]+)['"]$/);
		if (sideEffectImport?.groups?.specifier) {
			imports.push({ file, specifier: sideEffectImport.groups.specifier, kind: "static" });
			continue;
		}
		const fromImportOrExport = body.match(/\bfrom\s+['"](?<specifier>[^'"]+)['"]$/);
		if (fromImportOrExport?.groups?.specifier) {
			imports.push({ file, specifier: fromImportOrExport.groups.specifier, kind: "static" });
		}
	}

	const dynamicImport = /\bimport\s*\(\s*['"](?<specifier>[^'"]+)['"]\s*\)/g;
	for (const match of text.matchAll(dynamicImport)) {
		imports.push({ file, specifier: match.groups?.specifier ?? "", kind: "dynamic" });
	}
	return imports;
}

function resolveRelativeImport(importer: string, specifier: string): string {
	const resolved = path.resolve(path.dirname(importer), specifier);
	const candidates = [
		resolved,
		resolved.replace(/\.js$/, ".ts"),
		resolved.replace(/\.js$/, ".tsx"),
		resolved.replace(/\.mjs$/, ".mts"),
		`${resolved}.js`,
		`${resolved}.mjs`,
		`${resolved}.ts`,
		`${resolved}.tsx`,
		path.join(resolved, "index.js"),
		path.join(resolved, "index.mjs"),
		path.join(resolved, "index.ts"),
		path.join(resolved, "index.tsx"),
	];
	return candidates.find((candidate) => fs.existsSync(candidate) && fs.statSync(candidate).isFile()) ?? resolved;
}

describe("PR Walkthrough pack architecture boundary", () => {
	it("only imports packages, pack-local modules, or src/shared seams", () => {
		const violations: string[] = [];
		const files = walkSourceFiles(packSrc).sort();
		for (const file of files) {
			const source = fs.readFileSync(file, "utf-8");
			for (const site of collectImports(file, source)) {
				if (!site.specifier.startsWith(".")) continue;

				const resolved = resolveRelativeImport(file, site.specifier);
				if (isInDir(resolved, packRoot) || isInDir(resolved, sharedRoot)) continue;

				const forbiddenRoot = forbiddenCoreRoots.find((root) => isInDir(resolved, root));
				const reason = forbiddenRoot
					? `forbidden core import (${normalizePath(forbiddenRoot)})`
					: "relative import outside allowed pack-local/src/shared seams";
				violations.push(`${normalizePath(file)}: ${site.kind} import ${JSON.stringify(site.specifier)} resolves to ${normalizePath(resolved)} — ${reason}`);
			}
		}

		assert.deepEqual(violations, [], [
			"PR Walkthrough pack source must remain portable.",
			"Allowed imports: npm/package specifiers, files within market-packs/pr-walkthrough, or framework-neutral src/shared/** seams.",
			"Do not import src/ui, src/app, src/server, or other core app internals from the pack.",
			...violations,
		].join("\n"));
	});
});
